import React from 'react';
import { Link } from 'react-router-dom';
import { Helmet } from 'react-helmet-async';
import { useWishlist } from '../context/WishlistContext';
import { useAuth } from '../context/AuthContext';
import ProductCard from '../components/ProductCard';
import { useCart } from '../context/CartContext';

export default function WishlistPage({ embedded }) {
  const { user } = useAuth();
  const { products, loading } = useWishlist();
  const { addToCart } = useCart();

  const handleAdd = async (product) => {
    await addToCart(product, 1);
  };

  /** Map wishlist API products to ProductCard shape (imageUrl, rating, etc.) */
  const shaped = (p) => ({
    ...p,
    productId: p.slug,
    imageUrl: p.images?.[0]?.url || '',
    category: p.category?.slug || p.category || '',
    rating: Number(p.ratings) || 0,
    ratingCount: p.numReviews ?? 0,
    originalPrice: p.comparePrice,
    badge: p.isFeatured ? 'bestseller' : '',
    inStock: (p.stock ?? 0) > 0,
    stockQuantity: p.stock
  });

  if (!user) {
    return (
      <main className="section container text-center">
        <Helmet>
          <title>Wishlist | Nova Shop</title>
        </Helmet>
        <h1>Wishlist</h1>
        <p>Sign in to view saved items.</p>
        <Link to="/login" className="btn btn-primary">
          Sign in
        </Link>
      </main>
    );
  }

  const grid = (
    <>
      {loading ? (
        <p>Loading…</p>
      ) : products.length === 0 ? (
        <p className="empty-products-hint">
          No saved items yet.{' '}
          <Link to="/shop">Browse products</Link>
        </p>
      ) : (
        <div className="products-grid">
          {products.map((p) => (
            <ProductCard key={p._id} product={shaped(p)} onAddToCart={handleAdd} />
          ))}
        </div>
      )}
    </>
  );

  if (embedded) {
    return (
      <>
        <Helmet>
          <title>Wishlist | Nova Shop</title>
        </Helmet>
        <h2 style={{ fontSize: '1.25rem', marginBottom: '1rem' }}>Wishlist</h2>
        {grid}
      </>
    );
  }

  return (
    <main className="section wishlist-page">
      <Helmet>
        <title>Wishlist | Nova Shop</title>
      </Helmet>
      <div className="container">
        <header className="page-header">
          <h1>Wishlist</h1>
          <ol className="breadcrumb">
            <li>
              <Link to="/">Home</Link>
            </li>
            <li className="active">Wishlist</li>
          </ol>
        </header>
        {grid}
      </div>
    </main>
  );
}
